index 0000000..554f551
--- /dev/null
+++ b/non-standard/jsonschema/jsonschema_test.go
@@ -0,0 +1,202 @@
+package jsonschema
+
+import (
+	"encoding/json"
+	"testing"
+
+	"github.com/go-playground/assert/v2"
+)
+
+func unmarshalSchema(t *testing.T, b []byte) map[string]any {
+	t.Helper()
+	var m map[string]any
+	if err := json.Unmarshal(b, &m); err != nil {
+		t.Fatalf("unmarshal: %v", err)
+	}
+	return m
+}
+
+func prop(m map[string]any, name string) map[string]any {
+	props, _ := m["properties"].(map[string]any)
+	p, _ := props[name].(map[string]any)
+	return p
+}
+
+func requiredList(m map[string]any) []string {
+	r, _ := m["required"].([]any)
+	out := make([]string, len(r))
+	for i, v := range r {
+		out[i], _ = v.(string)
+	}
+	return out
+}
+
+func hasRequired(m map[string]any, name string) bool {
+	for _, r := range requiredList(m) {
+		if r == name {
+			return true
+		}
+	}
+	return false
+}
+
+func TestGenerate_simpleStruct(t *testing.T) {
+	type cfg struct {
+		Email string `json:"email" validate:"required,email"`
+		Port  int    `json:"port" validate:"gte=1,lte=65535"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	assert.Equal(t, "object", m["type"])
+	assert.Equal(t, true, hasRequired(m, "email"))
+	assert.Equal(t, "email", prop(m, "email")["format"])
+	port := prop(m, "port")
+	assert.Equal(t, "integer", port["type"])
+	assert.Equal(t, float64(1), port["minimum"])
+	assert.Equal(t, float64(65535), port["maximum"])
+}
+
+func TestGenerate_jsonTagNames(t *testing.T) {
+	type cfg struct {
+		Mail string `json:"e-mail" validate:"required"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	_, ok := m["properties"].(map[string]any)["e-mail"]
+	assert.Equal(t, true, ok)
+	assert.Equal(t, true, hasRequired(m, "e-mail"))
+}
+
+func TestGenerate_skipField(t *testing.T) {
+	type cfg struct {
+		Secret string `json:"secret" validate:"-"`
+		Public string `json:"public"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	props, _ := m["properties"].(map[string]any)
+	_, has := props["secret"]
+	assert.Equal(t, false, has)
+}
+
+func TestGenerate_omitemptyNotRequired(t *testing.T) {
+	type cfg struct {
+		X string `json:"x,omitempty" validate:"omitempty"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	_, ok := m["properties"].(map[string]any)["x"]
+	assert.Equal(t, true, ok)
+	assert.Equal(t, false, hasRequired(m, "x"))
+}
+
+func TestGenerate_nestedStructDive(t *testing.T) {
+	type inner struct {
+		Name string `json:"name" validate:"required"`
+	}
+	type cfg struct {
+		Inner inner `json:"inner" validate:"dive"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	innerSchema := prop(m, "inner")
+	innerProps, _ := innerSchema["properties"].(map[string]any)
+	assert.NotEqual(t, nil, innerProps)
+	nameSchema, _ := innerProps["name"].(map[string]any)
+	assert.Equal(t, "string", nameSchema["type"])
+	innerReq := requiredList(innerSchema)
+	assert.Equal(t, []string{"name"}, innerReq)
+}
+
+func TestGenerate_sliceDive(t *testing.T) {
+	type item struct {
+		ID int `json:"id" validate:"required"`
+	}
+	type cfg struct {
+		Items []item `json:"items" validate:"dive,gt=0"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	items := prop(m, "items")
+	assert.Equal(t, "array", items["type"])
+	itemSchema, _ := items["items"].(map[string]any)
+	itemProps, _ := itemSchema["properties"].(map[string]any)
+	assert.NotEqual(t, nil, itemProps)
+	assert.Equal(t, float64(1), items["minItems"])
+}
+
+func TestGenerate_mapDive(t *testing.T) {
+	type val struct {
+		Count int `json:"count" validate:"gte=0"`
+	}
+	type cfg struct {
+		Counts map[string]val `json:"counts" validate:"dive"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	counts := prop(m, "counts")
+	assert.Equal(t, "object", counts["type"])
+	addl, _ := counts["additionalProperties"].(map[string]any)
+	addlProps, _ := addl["properties"].(map[string]any)
+	assert.NotEqual(t, nil, addlProps["count"])
+}
+
+func TestGenerate_oneof(t *testing.T) {
+	type cfg struct {
+		Mode string `json:"mode" validate:"oneof=a b c"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	mode := prop(m, "mode")
+	enum, _ := mode["enum"].([]any)
+	assert.Equal(t, []any{"a", "b", "c"}, enum)
+}
+
+func TestGenerate_pointerNullable(t *testing.T) {
+	type cfg struct {
+		Label *string `json:"label"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	label := prop(m, "label")
+	assert.Equal(t, "string", label["type"])
+	assert.Equal(t, true, label["nullable"])
+	assert.Equal(t, false, hasRequired(m, "label"))
+}
+
+func TestGenerate_unsupportedCrossFieldIgnored(t *testing.T) {
+	type cfg struct {
+		A string `json:"a" validate:"required_without=Other"`
+		B string `json:"b"`
+	}
+	b, err := Generate(cfg{})
+	assert.Equal(t, nil, err)
+	m := unmarshalSchema(t, b)
+	_, ok := m["properties"].(map[string]any)["a"]
+	assert.Equal(t, true, ok)
+	_, has := m["dependentRequired"]
+	assert.Equal(t, false, has)
+}
+
+func TestGenerate_nonStructError(t *testing.T) {
+	_, err := Generate(42)
+	assert.NotEqual(t, nil, err)
+}
+
+func TestGenerateSchema_map(t *testing.T) {
+	type cfg struct {
+		Name string `validate:"required"`
+	}
+	m, err := GenerateSchema(cfg{})
+	assert.Equal(t, nil, err)
+	assert.Equal(t, defaultDraft, m["$schema"])
+}
diff --git a/non-standard/jsonschema/reflect.go b/non-standard/jsonschema/reflect.go
new file mode 100644
index 0000000..c2c459f
--- /dev/null
+++ b/non-standard/jsonschema/reflect.go
@@ -0,0 +1,320 @@
+package jsonschema
+
+import (
+	"reflect"
+)
+
+type generator struct {
+	cfg *config
+}
+
+func (g *generator) schemaForType(rt reflect.Type, tags *fieldTags) map[string]any {
+	for rt.Kind() == reflect.Ptr {
+		rt = rt.Elem()
+	}
+	schema := g.typeSchema(rt, tags)
+	if tags != nil && tags.afterDive != nil {
+		inner := g.schemaForType(rt, tags.afterDive)
+		switch rt.Kind() {
+		case reflect.Struct:
+			if props, ok := inner["properties"]; ok {
+				schema["properties"] = props
+			}
+			if req, ok := inner["required"]; ok {
+				schema["required"] = req
+			}
+		case reflect.Slice, reflect.Array:
+			schema["items"] = inner
+		case reflect.Map:
+			schema["additionalProperties"] = inner
+		}
+	}
+	return schema
+}
+
+func (g *generator) typeSchema(rt reflect.Type, tags *fieldTags) map[string]any {
+	schema := make(map[string]any)
+	if tags != nil && tags.booleanType {
+		schema["type"] = "boolean"
+		return schema
+	}
+	switch rt.Kind() {
+	case reflect.String:
+		schema["type"] = "string"
+		g.applyStringConstraints(schema, tags)
+	case reflect.Bool:
+		schema["type"] = "boolean"
+	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64,
+		reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64:
+		schema["type"] = "integer"
+		g.applyNumericConstraints(schema, tags, true)
+	case reflect.Float32, reflect.Float64:
+		schema["type"] = "number"
+		g.applyNumericConstraints(schema, tags, false)
+	case reflect.Slice, reflect.Array:
+		schema["type"] = "array"
+		elem := rt.Elem()
+		itemTags := &fieldTags{}
+		if tags != nil && tags.afterDive != nil {
+			itemTags = tags.afterDive
+		}
+		schema["items"] = g.schemaForType(elem, itemTags)
+		g.applyArrayConstraints(schema, tags)
+	case reflect.Map:
+		schema["type"] = "object"
+		valTags := &fieldTags{}
+		if tags != nil && tags.afterDive != nil {
+			valTags = tags.afterDive
+		}
+		schema["additionalProperties"] = g.schemaForType(rt.Elem(), valTags)
+	case reflect.Struct:
+		g.buildStructSchema(rt, schema, tags)
+	default:
+		schema["type"] = "string"
+	}
+	if tags != nil {
+		g.applyCommonConstraints(schema, tags)
+	}
+	return schema
+}
+
+func (g *generator) buildStructSchema(rt reflect.Type, schema map[string]any, tags *fieldTags) {
+	schema["type"] = "object"
+	props := make(map[string]any)
+	var required []string
+	for i := 0; i < rt.NumField(); i++ {
+		fld := rt.Field(i)
+		if fld.Anonymous {
+			embedded := fld.Type
+			for embedded.Kind() == reflect.Ptr {
+				embedded = embedded.Elem()
+			}
+			if embedded.Kind() == reflect.Struct {
+				sub := g.schemaForStructFields(embedded)
+				for k, v := range sub.props {
+					props[k] = v
+				}
+				required = append(required, sub.required...)
+			}
+			continue
+		}
+		if len(fld.PkgPath) > 0 {
+			continue
+		}
+		vtag := fld.Tag.Get(g.cfg.tagName)
+		ft := parseTags(vtag, g.cfg.tagName)
+		if ft.skip {
+			continue
+		}
+		name := g.fieldName(fld)
+		if name == "" || name == "-" {
+			continue
+		}
+		ftags := ft
+		if ft.dive && ft.afterDive != nil {
+			ftags = mergeTags(ft, ft.afterDive)
+		}
+		fieldSchema := g.fieldSchema(fld.Type, ft, ftags)
+		props[name] = fieldSchema
+		if g.fieldRequired(fld.Type, ft) {
+			required = append(required, name)
+		}
+	}
+	schema["properties"] = props
+	if len(required) > 0 {
+		schema["required"] = required
+	}
+}
+
+type structFieldsResult struct {
+	props    map[string]any
+	required []string
+}
+
+func (g *generator) schemaForStructFields(rt reflect.Type) structFieldsResult {
+	s := make(map[string]any)
+	g.buildStructSchema(rt, s, nil)
+	props, _ := s["properties"].(map[string]any)
+	req, _ := s["required"].([]string)
+	return structFieldsResult{props: props, required: req}
+}
+
+func (g *generator) fieldSchema(rt reflect.Type, ft *fieldTags, constraintTags *fieldTags) map[string]any {
+	isPtr := rt.Kind() == reflect.Ptr
+	elem := rt
+	for elem.Kind() == reflect.Ptr {
+		elem = elem.Elem()
+	}
+	innerTags := ft
+	if ft.dive && ft.afterDive != nil {
+		innerTags = ft.afterDive
+	} else if !ft.dive {
+		innerTags = constraintTags
+	}
+	schema := g.schemaForType(elem, innerTags)
+	if isPtr && !g.fieldRequired(rt, ft) {
+		schema["nullable"] = true
+	}
+	return schema
+}
+
+func (g *generator) fieldRequired(rt reflect.Type, ft *fieldTags) bool {
+	if ft.omitEmpty || ft.omitNil || ft.omitZero {
+		return false
+	}
+	if !ft.required {
+		return false
+	}
+	elem := rt
+	for elem.Kind() == reflect.Ptr {
+		elem = elem.Elem()
+	}
+	if elem.Kind() == reflect.Struct {
+		return g.cfg.requiredStructEnable
+	}
+	return true
+}
+
+func (g *generator) fieldName(fld reflect.StructField) string {
+	if g.cfg.useJSONTag {
+		jt := fld.Tag.Get("json")
+		if jt != "" {
+			name := jt
+			if idx := indexComma(jt); idx >= 0 {
+				name = jt[:idx]
+			}
+			if name == "-" {
+				return ""
+			}
+			return name
+		}
+	}
+	return fld.Name
+}
+
+func indexComma(s string) int {
+	for i := 0; i < len(s); i++ {
+		if s[i] == ',' {
+			return i
+		}
+	}
+	return -1
+}
+
+func (g *generator) applyCommonConstraints(schema map[string]any, tags *fieldTags) {
+	if tags == nil {
+		return
+	}
+	if len(tags.oneof) > 0 {
+		enums := make([]any, len(tags.oneof))
+		for i, v := range tags.oneof {
+			enums[i] = v
+		}
+		schema["enum"] = enums
+	}
+	if tags.format != "" {
+		schema["format"] = tags.format
+	}
+	if tags.uniqueItems {
+		schema["uniqueItems"] = true
+	}
+}
+
+func (g *generator) applyStringConstraints(schema map[string]any, tags *fieldTags) {
+	if tags == nil {
+		return
+	}
+	if tags.minLen != nil {
+		schema["minLength"] = *tags.minLen
+	}
+	if tags.maxLen != nil {
+		schema["maxLength"] = *tags.maxLen
+	}
+	if tags.min != nil {
+		schema["minLength"] = int(*tags.min)
+	}
+	if tags.max != nil {
+		schema["maxLength"] = int(*tags.max)
+	}
+	if tags.eqStr != "" {
+		schema["minLength"] = len(tags.eqStr)
+		schema["maxLength"] = len(tags.eqStr)
+	}
+}
+
+func (g *generator) applyNumericConstraints(schema map[string]any, tags *fieldTags, integer bool) {
+	if tags == nil {
+		return
+	}
+	setNum := func(key string, v float64) {
+		if integer {
+			schema[key] = int(v)
+		} else {
+			schema[key] = v
+		}
+	}
+	if tags.eq != nil {
+		setNum("minimum", *tags.eq)
+		setNum("maximum", *tags.eq)
+	}
+	if tags.min != nil {
+		setNum("minimum", *tags.min)
+	}
+	if tags.max != nil {
+		setNum("maximum", *tags.max)
+	}
+	if tags.gt != nil {
+		schema["exclusiveMinimum"] = *tags.gt
+		if integer {
+			schema["exclusiveMinimum"] = int(*tags.gt)
+		}
+	}
+	if tags.gte != nil {
+		setNum("minimum", *tags.gte)
+	}
+	if tags.lt != nil {
+		schema["exclusiveMaximum"] = *tags.lt
+		if integer {
+			schema["exclusiveMaximum"] = int(*tags.lt)
+		}
+	}
+	if tags.lte != nil {
+		setNum("maximum", *tags.lte)
+	}
+}
+
+func (g *generator) applyArrayConstraints(schema map[string]any, tags *fieldTags) {
+	if tags == nil {
+		return
+	}
+	if tags.minLen != nil {
+		schema["minItems"] = *tags.minLen
+	}
+	if tags.maxLen != nil {
+		schema["maxItems"] = *tags.maxLen
+	}
+	if tags.min != nil {
+		schema["minItems"] = int(*tags.min)
+	}
+	if tags.max != nil {
+		schema["maxItems"] = int(*tags.max)
+	}
+	if tags.gt != nil {
+		n := int(*tags.gt)
+		schema["minItems"] = n + 1
+	}
+	if tags.gte != nil {
+		schema["minItems"] = int(*tags.gte)
+	}
+	if tags.lt != nil {
+		schema["maxItems"] = int(*tags.lt) - 1
+	}
+	if tags.lte != nil {
+		schema["maxItems"] = int(*tags.lte)
+	}
+	if tags.eq != nil {
+		n := int(*tags.eq)
+		schema["minItems"] = n
+		schema["maxItems"] = n
+	}
+}
diff --git a/non-standard/jsonschema/tags.go b/non-standard/jsonschema/tags.go
new file mode 100644
index 0000000..117edb1
--- /dev/null
+++ b/non-standard/jsonschema/tags.go
@@ -0,0 +1,216 @@
+package jsonschema
+
+import (
+	"strconv"
+	"strings"
+)
+
+const (
+	tagSeparator    = ","
+	tagKeySeparator = "="
+	skipTag         = "-"
+	diveTag         = "dive"
+	keysTag         = "keys"
+	endKeysTag      = "endkeys"
+)
+
+type fieldTags struct {
+	skip           bool
+	required       bool
+	omitEmpty      bool
+	omitNil        bool
+	omitZero       bool
+	dive           bool
+	keys           bool
+	afterDive      *fieldTags
+	min            *float64
+	max            *float64
+	minLen         *int
+	maxLen         *int
+	eq             *float64
+	eqStr          string
+	gt             *float64
+	gte            *float64
+	lt             *float64
+	lte            *float64
+	oneof          []string
+	format         string
+	uniqueItems    bool
+	booleanType    bool
+}
+
+func parseTags(tag string, tagName string) *fieldTags {
+	if tag == "" {
+		return &fieldTags{}
+	}
+	if tag == skipTag {
+		return &fieldTags{skip: true}
+	}
+	return parseTagsRecursive(tag)
+}
+
+func parseTagsRecursive(tag string) *fieldTags {
+	ft := &fieldTags{}
+	tags := strings.Split(tag, tagSeparator)
+	var diveIdx int = -1
+	for i := 0; i < len(tags); i++ {
+		t := strings.TrimSpace(tags[i])
+		switch t {
+		case skipTag:
+			ft.skip = true
+			return ft
+		case diveTag:
+			ft.dive = true
+			diveIdx = i
+		case keysTag:
+			ft.keys = true
+			for i+1 < len(tags) && tags[i+1] != endKeysTag {
+				i++
+			}
+		case endKeysTag:
+		case "omitempty":
+			ft.omitEmpty = true
+		case "omitnil":
+			ft.omitNil = true
+		case "omitzero":
+			ft.omitZero = true
+		case "required":
+			ft.required = true
+		case "unique":
+			ft.uniqueItems = true
+		case "boolean":
+			ft.booleanType = true
+		case "email", "url", "uri", "uuid", "uuid4", "ipv4", "ipv6":
+			ft.format = t
+		default:
+			applyParamTag(ft, t)
+		}
+	}
+	if diveIdx >= 0 && diveIdx+1 < len(tags) {
+		rest := strings.Join(tags[diveIdx+1:], tagSeparator)
+		// strip keys/endkeys block from dive tail
+		if idx := strings.Index(rest, keysTag); idx >= 0 {
+			if end := strings.Index(rest, endKeysTag); end >= 0 {
+				after := rest[end+len(endKeysTag):]
+				rest = strings.TrimPrefix(after, tagSeparator)
+			}
+		}
+		rest = strings.TrimPrefix(rest, tagSeparator)
+		if rest != "" && rest != keysTag {
+			ft.afterDive = parseTagsRecursive(rest)
+		} else {
+			ft.afterDive = &fieldTags{}
+		}
+	}
+	return ft
+}
+
+func applyParamTag(ft *fieldTags, t string) {
+	parts := strings.SplitN(t, tagKeySeparator, 2)
+	key := parts[0]
+	param := ""
+	if len(parts) > 1 {
+		param = parts[1]
+	}
+	switch key {
+	case "min", "max", "eq", "gt", "gte", "lt", "lte":
+		if f, err := strconv.ParseFloat(param, 64); err == nil {
+			switch key {
+			case "min":
+				ft.min = &f
+			case "max":
+				ft.max = &f
+			case "eq":
+				ft.eq = &f
+			case "gt":
+				ft.gt = &f
+			case "gte":
+				ft.gte = &f
+			case "lt":
+				ft.lt = &f
+			case "lte":
+				ft.lte = &f
+			}
+		}
+	case "len":
+		if n, err := strconv.Atoi(param); err == nil {
+			switch {
+			case ft.minLen == nil:
+				ft.minLen = &n
+				ft.maxLen = &n
+			default:
+				ft.minLen = &n
+				ft.maxLen = &n
+			}
+		}
+	case "oneof":
+		ft.oneof = strings.Fields(param)
+	default:
+		// cross-field and unknown tags ignored in v1
+	}
+	if key == "eq" && param != "" && ft.eq == nil {
+		ft.eqStr = param
+	}
+}
+
+func mergeTags(parent, child *fieldTags) *fieldTags {
+	if child == nil {
+		return parent
+	}
+	out := *parent
+	if child.required {
+		out.required = true
+	}
+	if child.omitEmpty {
+		out.omitEmpty = true
+	}
+	if child.omitNil {
+		out.omitNil = true
+	}
+	if child.omitZero {
+		out.omitZero = true
+	}
+	if child.min != nil {
+		out.min = child.min
+	}
+	if child.max != nil {
+		out.max = child.max
+	}
+	if child.minLen != nil {
+		out.minLen = child.minLen
+	}
+	if child.maxLen != nil {
+		out.maxLen = child.maxLen
+	}
+	if child.eq != nil {
+		out.eq = child.eq
+	}
+	if child.eqStr != "" {
+		out.eqStr = child.eqStr
+	}
+	if child.gt != nil {
+		out.gt = child.gt
+	}
+	if child.gte != nil {
+		out.gte = child.gte
+	}
+	if child.lt != nil {
+		out.lt = child.lt
+	}
+	if child.lte != nil {
+		out.lte = child.lte
+	}
+	if len(child.oneof) > 0 {
+		out.oneof = child.oneof
+	}
+	if child.format != "" {
+		out.format = child.format
+	}
+	if child.uniqueItems {
+		out.uniqueItems = true
+	}
+	if child.booleanType {
+		out.booleanType = true
+	}
+	return &out
+}
